import time

class ColdChamberAPI:
    """Interface for controlling the cricket cold-chamber."""

    def __init__(self, chamber_id: int):
        self.chamber_id = chamber_id
        self.current_temp = 20.0  # Celsius
        self.is_active = False

    def set_temperature(self, target_temp: float):
        """
        Sets the target temperature for the chamber.
        Safe operating range: 0.0C to 15.0C.
        """
        if not (0.0 <= target_temp <= 15.0):
            raise ValueError(f"Temperature {target_temp}C out of safe hardware range.")
        print(f"Chamber {self.chamber_id}: Cooling to {target_temp}C...")
        self.current_temp = target_temp

    def start_batch(self):
        """Starts the batch processing cycle (loading). Mechanical loading takes 4 minutes."""
        self.is_active = True
        print(f"Chamber {self.chamber_id}: Batch loaded and processing started.")

    def stop_batch(self):
        """Stops the batch processing cycle (unloading). Mechanical unloading takes 4 minutes."""
        self.is_active = False
        print(f"Chamber {self.chamber_id}: Batch processing stopped and unloaded.")

    def get_status(self):
        """Returns the current status and temperature of the chamber."""
        return {
            "is_active": self.is_active,
            "current_temp": self.current_temp
        }

import logging

def setup_logger(name: str):
    logging.basicConfig(level=logging.INFO)
    return logging.getLogger(name)

def calculate_shift_metrics(processed_kg: float, elapsed_time_hours: float):
    return {
        "throughput_per_hour": processed_kg / elapsed_time_hours,
        "is_on_track": (processed_kg / elapsed_time_hours) >= 100
    }

